// Normalize Evolution API message payload across event shapes
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const isGroup = remoteJid.endsWith('@g.us');
const fromMe = !!key.fromMe;

// Sender phone — in groups it's `participant`, in DMs it's `remoteJid`
const senderJid = isGroup ? (key.participant || '') : remoteJid;
const senderPhone = senderJid.split('@')[0].replace(/[^0-9]/g, '');

// Extract text — handle multiple message envelope variants
const m = data.message || {};
const text = (
  m.conversation ||
  m.extendedTextMessage?.text ||
  m.imageMessage?.caption ||
  m.videoMessage?.caption ||
  ''
).trim();

return [{ json: {
  event: body.event || data.event || 'unknown',
  isGroup,
  fromMe,
  groupJid: isGroup ? remoteJid : null,
  senderPhone,
  senderJid,
  text,
  textLower: text.toLowerCase(),
  raw: body,
}}];

// Build a DM reply based on RPC result
const rpc = $input.first().json;
const sender = $('Normalize Payload').first().json;
const msg = rpc?.message || (rpc?.ok ? '✅ Bonus terverifikasi!' : '❌ Verifikasi gagal — coba lagi atau hubungi admin.');
return [{ json: { ...sender, dmText: msg, rpc } }];
